def validate_monto_nested(m):
    if m is not None:
        if isinstance(m, int):
            if m >= 0:
                if m <= 10000:
                    return "accept"
                else:
                    return "review"
            else:
                return "reject"
        else:
            return "reject"
    else:
        return "review"

def validate_monto_guards(m):
    if m is None:
        return "review"
    if not isinstance(m, int) or isinstance(m, bool):
        return "reject"
    if m < 0:
        return "reject"
    if m <= 10000:
        return "accept"
    return "review"

for m in [None, "x", -1, 0, 500, 20000]:
    print(m, nested=validate_monto_nested(m) if not isinstance(m, str) else validate_monto_nested(m),
          guards=validate_monto_guards(m) if True else None)
    print(m, "→", validate_monto_nested(m), validate_monto_guards(m))
