def decide(row):
    if row.get("region") not in {"Lima", "Arequipa", "Cusco"}:
        return "reject"
    monto = row.get("monto")
    if monto is None:
        return "review"
    if monto < 0:
        return "reject"
    if monto > 10000:
        return "review"
    return "accept"

for row in [
    {"region": "Lima", "monto": 100},
    {"region": "Piura", "monto": 100},
    {"region": "Cusco", "monto": None},
    {"region": "Lima", "monto": -5},
    {"region": "Lima", "monto": 50000},
]:
    print(row, "→", decide(row))
