def explain(row):
    reasons = []
    if row.get("doc") not in {"DNI", "CE"}:
        reasons.append("doc_not_allowed")
    if row.get("edad") is None:
        reasons.append("edad_missing")
    if not reasons:
        return "accept", []
    if "edad_missing" in reasons and "doc_not_allowed" not in reasons:
        return "review", reasons
    return "reject", reasons

for r in [{"doc": "DNI", "edad": 20}, {"doc": "RUC", "edad": 20}, {"doc": "DNI", "edad": None}]:
    print(r, "→", explain(r))
